import{_ as e,c as t,o as i,a3 as a}from"./chunks/framework.D5qxx6u8.js";const u=JSON.parse('{"title":"CSS","description":"","frontmatter":{},"headers":[],"relativePath":"interview/frontend/css.md","filePath":"interview/frontend/css.md","lastUpdated":1775309204000}'),l={name:"interview/frontend/css.md"},o=a('<h1 id="css" tabindex="-1">CSS <a class="header-anchor" href="#css" aria-label="Permalink to &quot;CSS&quot;">​</a></h1><h2 id="bfc-是什么" tabindex="-1">BFC 是什么？ <a class="header-anchor" href="#bfc-是什么" aria-label="Permalink to &quot;BFC 是什么？&quot;">​</a></h2><p>需要先提出CSS布局中遇到的问题：</p><ul><li>外边距塌陷</li><li>子元素浮动导致父容器高度塌陷</li><li>浮动元素遮挡其他普通元素</li><li>等等</li></ul><p>为了解决上面这些问题提出了BFC：</p><p>Web 页面中一个独立的渲染区域，这个区域内部元素的布局和渲染不会影响到外部元素，外部元素的布局和渲染也不会影响到该区域内部。简单来说，BFC就是一个&#39;隔离的容器&#39;。</p><p><strong>触发条件</strong>：</p><ul><li><p>overflow：hidden ✅️</p></li><li><p>float：left / right</p></li><li><p>position：absolute / fixed</p></li><li><p>display：inline-block / flow-root（现代标准推荐）</p></li></ul>',8),s=[o];function r(n,c,p,d,_,f){return i(),t("div",null,s)}const S=e(l,[["render",r]]);export{u as __pageData,S as default};
